      (forall (i: Z), (0 <= i && i < n) => (0 <= l[i] && l[i] < 100)) &&
      ret == sum(sublist(0, i, l)) &&
      IntArray::full(a, n, l)
    */
  while (i < n) {
    ret += a[i];
    ++i;
  }
  return ret;
}

